// And groups predicates with the AND operator between them.
func And(predicates ...predicate.PortalBanner) predicate.PortalBanner {
	return predicate.PortalBanner(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.PortalBanner) predicate.PortalBanner {
	return predicate.PortalBanner(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.PortalBanner) predicate.PortalBanner {
	return predicate.PortalBanner(sql.NotPredicates(p))
}
